// Central definition of every question in the Weekend Reality Check™ flow.
// Each day (Friday / Saturday / Sunday) reuses the exact same 5 sub-questions,
// generated by makeDayQuestions() so copy + scoring stay perfectly in sync.

export const GOAL_OPTIONS = [
  { value: "lose_fat", label: "Lose fat", sub: "Drop the belly. Look better." },
  { value: "build_muscle", label: "Build muscle", sub: "Get bigger and stronger." },
  { value: "get_fitter", label: "Get fitter", sub: "More energy, move better." },
  { value: "feel_better", label: "Just feel better", sub: "Less foggy, more like myself." },
];

export const GENDER_OPTIONS = [
  { value: "male", label: "Male" },
  { value: "female", label: "Female" },
  { value: "unspecified", label: "Prefer not to say" },
];

// Index-based scale so scoring.js can read option.meta directly.
export const ALCOHOL_OPTIONS = [
  { value: "none", label: "None", sub: "Didn't touch it.", drinks: 0 },
  { value: "low", label: "1–2 drinks", sub: "Kept it sensible.", drinks: 1.5 },
  { value: "mid", label: "3–5 drinks", sub: "Proper session if I'm honest.", drinks: 4 },
  { value: "high", label: "6+ drinks", sub: "Lost count.", drinks: 8 },
];

export const TAKEAWAY_OPTIONS = [
  { value: "none", label: "None", sub: "Cooked at home or skipped it.", cal: 0 },
  { value: "one", label: "One takeaway", sub: "Just the one.", cal: 700 },
  { value: "multiple", label: "More than one", sub: "It got out of hand.", cal: 1400 },
];

export const DESSERT_OPTIONS = [
  { value: "none", label: "None", sub: "Didn't go near it.", cal: 0 },
  { value: "one", label: "One treat", sub: "Kept it in check.", cal: 350 },
  { value: "multiple", label: "Multiple treats", sub: "It got out of hand.", cal: 700 },
];

export const SNACK_OPTIONS = [
  { value: "none", label: "None", sub: "Barely anything.", cal: 0 },
  { value: "some", label: "A bit here and there", sub: "Some grazing throughout the day.", cal: 250 },
  { value: "constant", label: "All day grazing", sub: "Mouth never really stopped.", cal: 600 },
];

export const STEPS_OPTIONS = [
  { value: "low", label: "Under 5k", sub: "Barely moved.", band: 0, adjust: 300 },
  { value: "mid", label: "5k–10k", sub: "Ticking over.", band: 1, adjust: 0 },
  { value: "high", label: "10k+", sub: "Got out and moved.", band: 2, adjust: -300 },
];

const DAY_META = {
  friday: { title: "Friday", emoji: "🍻" },
  saturday: { title: "Saturday", emoji: "🍕" },
  sunday: { title: "Sunday", emoji: "🛋️" },
};

function makeDayQuestions(day) {
  const { title } = DAY_META[day];
  return [
    {
      id: `${day}_alcohol`,
      screen: day,
      section: title,
      type: "choice",
      field: `${day}_alcohol`,
      question: `Be honest with me. How much did you drink on ${title}?`,
      options: ALCOHOL_OPTIONS,
    },
    {
      id: `${day}_takeaway`,
      screen: day,
      section: title,
      type: "choice",
      field: `${day}_takeaway`,
      question: `Did you order a takeaway on ${title}?`,
      options: TAKEAWAY_OPTIONS,
    },
    {
      id: `${day}_dessert`,
      screen: day,
      section: title,
      type: "choice",
      field: `${day}_dessert`,
      question: `Dessert or sweet treats on ${title}?`,
      options: DESSERT_OPTIONS,
    },
    {
      id: `${day}_snacks`,
      screen: day,
      section: title,
      type: "choice",
      field: `${day}_snacks`,
      question: `How much were you snacking on ${title}? Be real with me.`,
      options: SNACK_OPTIONS,
    },
    {
      id: `${day}_steps`,
      screen: day,
      section: title,
      type: "choice",
      field: `${day}_steps`,
      question: `Roughly how many steps did you get on ${title}?`,
      options: STEPS_OPTIONS,
    },
  ];
}

export function buildFlow() {
  return [
    { id: "splash", screen: "splash", type: "splash" },
    { id: "landing", screen: "landing", type: "landing" },

    // About you
    {
      id: "age",
      screen: "about",
      section: "About You",
      type: "number",
      field: "age",
      question: "How old are you?",
      unitLabel: "years",
      min: 16,
      max: 90,
      step: 1,
      default: 30,
    },
    {
      id: "gender",
      screen: "about",
      section: "About You",
      type: "choice",
      field: "gender",
      question: "Gender?",
      options: GENDER_OPTIONS,
    },
    {
      id: "height",
      screen: "about",
      section: "About You",
      type: "height",
      field: "heightCm",
      question: "How tall are you?",
    },
    {
      id: "weight",
      screen: "about",
      section: "About You",
      type: "weight",
      field: "weightKg",
      question: "What do you weigh?",
    },
    {
      id: "goal",
      screen: "about",
      section: "About You",
      type: "choice",
      field: "goal",
      question: "What's the actual goal here? Be straight with me.",
      options: GOAL_OPTIONS,
    },

    // Friday / Saturday / Sunday
    ...makeDayQuestions("friday"),
    ...makeDayQuestions("saturday"),
    ...makeDayQuestions("sunday"),

    { id: "scan", screen: "scan", type: "scan" },
    { id: "results", screen: "results", type: "results" },
    { id: "reset", screen: "reset", type: "reset" },
    { id: "cta", screen: "cta", type: "cta" },
    { id: "email", screen: "email", type: "email" },
  ];
}

export const QUESTION_SECTIONS = ["About You", "Friday", "Saturday", "Sunday"];
